import random
from dataclasses import dataclass, field
from typing import Optional, List
from enum import Enum

class DeploymentDecision(Enum):
    WAIT = "wait"
    PROMOTE = "promote" 
    ROLLBACK = "rollback"

@dataclass
class ExecutionRecord:
    version: str
    success: bool
    fidelity: float

@dataclass
class VersionMetrics:
    version: str
    total_executions: int = 0
    successes: int = 0
    fidelity_sum: float = 0.0

    @property
    def success_rate(self) -> float:
        if self.total_executions == 0:
            return 0.0
        return self.successes / self.total_executions

    @property
    def avg_fidelity(self) -> float:
        if self.total_executions == 0:
            return 0.0
        return self.fidelity_sum / self.total_executions

class CanaryRouter:
    def __init__(
        self,
        canary_percentage: float = 0.1,
        min_samples: int = 100,
        success_threshold: float = 0.95,
        fidelity_threshold: float = 0.85
    ):
        self.canary_percentage = canary_percentage
        self.min_samples = min_samples
        self.success_threshold = success_threshold
        self.fidelity_threshold = fidelity_threshold

        self.stable_version = "v1.0.0"
        self.canary_version: Optional[str] = None
        self.stable_metrics = VersionMetrics("v1.0.0")
        self.canary_metrics: Optional[VersionMetrics] = None

    def start_canary(self, version: str):
        """Start a new canary deployment."""
        self.canary_version = version
        self.canary_metrics = VersionMetrics(version)

    def route_request(self) -> str:
        """Return which version should handle this request."""
        if self.canary_version is None:
            return self.stable_version

        if random.random() < self.canary_percentage:
            return self.canary_version
        return self.stable_version

    def record_execution(self, record: ExecutionRecord):
        """Record an execution result."""
        if record.version == self.canary_version and self.canary_metrics:
            metrics = self.canary_metrics
        else:
            metrics = self.stable_metrics

        metrics.total_executions += 1
        if record.success:
            metrics.successes += 1
        metrics.fidelity_sum += record.fidelity

    def evaluate(self) -> DeploymentDecision:
        """Evaluate if canary should be promoted or rolled back."""
        if self.canary_version is None or self.canary_metrics is None:
            return DeploymentDecision.WAIT

        # Need minimum samples
        if self.canary_metrics.total_executions < self.min_samples:
            return DeploymentDecision.WAIT

        # Check success rate
        if self.canary_metrics.success_rate < self.success_threshold:
            return DeploymentDecision.ROLLBACK

        # Check fidelity
        if self.canary_metrics.avg_fidelity < self.fidelity_threshold:
            return DeploymentDecision.ROLLBACK

        return DeploymentDecision.PROMOTE

    def promote(self):
        """Promote canary to stable."""
        if self.canary_version:
            self.stable_version = self.canary_version
            self.stable_metrics = self.canary_metrics
            self.canary_version = None
            self.canary_metrics = None

    def rollback(self):
        """Rollback canary deployment."""
        self.canary_version = None
        self.canary_metrics = None
